INSERT INTO `products` (`_id`, `name`, `category`, `subCategory`, `about`, `description`, `price`, `offerPrice`, `footwear_sizes`, `colors`, `created_at`, `sizes`) VALUES
(25, 'Genteez Jotaro Digital Printed T Shirt For Men', 'Clothing & Style', 'Men', '<p><strong>Key Features:</strong></p><ol><li data-list=\"bullet\"><span class=\"ql-ui\" contenteditable=\"false\"></span>100% premium cotton for softness and durability</li><li data-list=\"bullet\"><span class=\"ql-ui\" contenteditable=\"false\"></span>Eye-catching Jotaro digital print</li><li data-list=\"bullet\"><span class=\"ql-ui\" contenteditable=\"false\"></span>Modern, comfortable fit for everyday wear</li><li data-list=\"bullet\"><span class=\"ql-ui\" contenteditable=\"false\"></span>Easy to wash, colors stay vibrant</li><li data-list=\"bullet\"><span class=\"ql-ui\" contenteditable=\"false\"></span>Ideal for casual outings, fan events, or gifting</li><li data-list=\"bullet\"><span class=\"ql-ui\" contenteditable=\"false\"></span>Unisex appeal for style-conscious men and anime enthusiasts</li><li data-list=\"bullet\"><span class=\"ql-ui\" contenteditable=\"false\"></span>Fade-resistant and shrink-resistant material</li></ol>', '<p>Unleash your style and showcase your fandom with the <strong>Genteez Jotaro Digital Printed T-Shirt</strong>. Designed for men who value both comfort and bold fashion, this t-shirt combines premium quality with striking anime-inspired design. The vivid digital print of Jotaro captures every detail, making it a statement piece that stands out wherever you go.</p><p>Made from <strong>100% soft, breathable cotton</strong>, this t-shirt ensures all-day comfort, whether youŌĆÖre out with friends, attending an anime event, or just relaxing at home. Its modern, regular fit flatters all body types, while durable stitching and fade-resistant fabric keep it looking sharp even after multiple washes. The classic crew neck and lightweight design make it versatile and easy to style with jeans, shorts, or joggers.</p><p>Perfect as a casual outfit or a thoughtful gift for anime enthusiasts, the <strong>Genteez Jotaro T-Shirt</strong> is more than just clothingŌĆöitŌĆÖs a statement of personality, fandom, and style.</p>', 1600, 1250, '[]', '[\"White\",\"Black\"]', '2026-03-08 10:38:12', '[\"[\\\"S\\\",\\\"M\\\",\\\"L\\\",\\\"XL\\\",\\\"XXL\\\"]\"]'),
(26, 'Toor Traders Biker Black Leather Jacket With Removable Hood', 'Clothing & Style', 'Men', '<p><strong>Key Features</strong></p><ol><li data-list=\"bullet\"><span class=\"ql-ui\" contenteditable=\"false\"></span>Premium quality leather construction for durability and long-lasting wear</li><li data-list=\"bullet\"><span class=\"ql-ui\" contenteditable=\"false\"></span>Stylish <strong>biker design</strong> that adds a bold and modern look</li><li data-list=\"bullet\"><span class=\"ql-ui\" contenteditable=\"false\"></span><strong>Removable hood</strong> for versatile styling (casual or classic biker look)</li><li data-list=\"bullet\"><span class=\"ql-ui\" contenteditable=\"false\"></span>Soft inner lining for extra warmth and comfort</li><li data-list=\"bullet\"><span class=\"ql-ui\" contenteditable=\"false\"></span>Front <strong>zipper closure</strong> for easy wear and secure fit</li><li data-list=\"bullet\"><span class=\"ql-ui\" contenteditable=\"false\"></span>Multiple pockets for convenient storage of essentials</li><li data-list=\"bullet\"><span class=\"ql-ui\" contenteditable=\"false\"></span>Adjustable cuffs and waist for a better, customized fit</li><li data-list=\"bullet\"><span class=\"ql-ui\" contenteditable=\"false\"></span>Wind-resistant material ideal for riding and outdoor use</li></ol>', '<ol><li data-list=\"bullet\"><span class=\"ql-ui\" contenteditable=\"false\"></span><span style=\"background-color: rgb(255, 255, 255); color: rgb(0, 0, 0);\">100% Real Sheepskin Black / Brown Leather, Polyester Lining, Fleece, Rib, Heavy Duty YKK/Brass Zipper and Snap Metal Buttons</span></li><li data-list=\"bullet\"><span class=\"ql-ui\" contenteditable=\"false\"></span><span style=\"background-color: rgb(255, 255, 255); color: rgb(0, 0, 0);\">Front Zipper Closure;</span></li><li data-list=\"bullet\"><span class=\"ql-ui\" contenteditable=\"false\"></span><span style=\"background-color: rgb(255, 255, 255); color: rgb(0, 0, 0);\">Windproof and Waterproof;</span></li><li data-list=\"bullet\"><span class=\"ql-ui\" contenteditable=\"false\"></span><span style=\"background-color: rgb(255, 255, 255); color: rgb(0, 0, 0);\">Removable Hood;</span></li><li data-list=\"bullet\"><span class=\"ql-ui\" contenteditable=\"false\"></span><span style=\"background-color: rgb(255, 255, 255); color: rgb(0, 0, 0);\">Two style design between stylish hooded riding jacket and casual Crewneck stand collar winter fashion jacket;</span></li><li data-list=\"bullet\"><span class=\"ql-ui\" contenteditable=\"false\"></span><span style=\"background-color: rgb(255, 255, 255); color: rgb(0, 0, 0);\">Two Chest Side Decorative Zip-fastening Pockets;</span></li><li data-list=\"bullet\"><span class=\"ql-ui\" contenteditable=\"false\"></span><span style=\"background-color: rgb(255, 255, 255); color: rgb(0, 0, 0);\">One Chest Right Flapped Pocket;</span></li><li data-list=\"bullet\"><span class=\"ql-ui\" contenteditable=\"false\"></span><span style=\"background-color: rgb(255, 255, 255); color: rgb(0, 0, 0);\">Two Waist Side Slit Pockets &amp; One inside Concealment Pockets;</span></li><li data-list=\"bullet\"><span class=\"ql-ui\" contenteditable=\"false\"></span><span style=\"background-color: rgb(255, 255, 255); color: rgb(0, 0, 0);\">Smooth Heavy Duty YKK/Brass Full Length Metal Zippers at Front; Decorative Pockets and with Detachable Hood;</span></li><li data-list=\"bullet\"><span class=\"ql-ui\" contenteditable=\"false\"></span><span style=\"background-color: rgb(255, 255, 255); color: rgb(0, 0, 0);\">Button Closure for Stand Collar and Shoulder Straps for wind protection.</span></li><li data-list=\"bullet\"><span class=\"ql-ui\" contenteditable=\"false\"></span><span style=\"background-color: rgb(255, 255, 255); color: rgb(0, 0, 0);\">Smooth, stylish and plain unique appearance forever has given this a pioneer, luxurious, glamorous and embroidery furry look;</span></li><li data-list=\"bullet\"><span class=\"ql-ui\" contenteditable=\"false\"></span><span style=\"background-color: rgb(255, 255, 255); color: rgb(0, 0, 0);\">Finest quality of stitching has been done across the shoulders, pockets, arms and cuffs by our artisans to make it more splendid outlook;</span></li><li data-list=\"bullet\"><span class=\"ql-ui\" contenteditable=\"false\"></span><span style=\"background-color: rgb(255, 255, 255); color: rgb(0, 0, 0);\">Lightweight &amp; comfortable to wear;</span></li><li data-list=\"bullet\"><span class=\"ql-ui\" contenteditable=\"false\"></span><span style=\"background-color: rgb(255, 255, 255); color: rgb(0, 0, 0);\">Dry Clean Recommended;</span></li></ol>', 6195, 4999, '[]', '[]', '2026-03-08 12:40:27', '[\"[\\\"S\\\",\\\"M\\\",\\\"L\\\",\\\"XL\\\",\\\"XXL\\\"]\"]'),
(27, 'Stylish Winter Pullover for Men Premium Streetwear', 'Clothing & Style', 'Men', '<p><strong>Key Features </strong></p><ol><li data-list=\"bullet\"><span class=\"ql-ui\" contenteditable=\"false\"></span><strong>Premium quality fabric</strong> for superior comfort and durability</li><li data-list=\"bullet\"><span class=\"ql-ui\" contenteditable=\"false\"></span><strong>Warm and cozy material</strong> ideal for winter and cold weather</li><li data-list=\"bullet\"><span class=\"ql-ui\" contenteditable=\"false\"></span><strong>Modern streetwear design</strong> for a trendy and fashionable look</li><li data-list=\"bullet\"><span class=\"ql-ui\" contenteditable=\"false\"></span><strong>Soft inner lining</strong> that provides extra warmth and comfort</li><li data-list=\"bullet\"><span class=\"ql-ui\" contenteditable=\"false\"></span><strong>Regular fit style</strong> suitable for everyday casual wear</li><li data-list=\"bullet\"><span class=\"ql-ui\" contenteditable=\"false\"></span><strong>Breathable fabric</strong> that keeps you comfortable throughout the day</li><li data-list=\"bullet\"><span class=\"ql-ui\" contenteditable=\"false\"></span><strong>Ribbed cuffs and hem</strong> for a secure and stylish fit</li><li data-list=\"bullet\"><span class=\"ql-ui\" contenteditable=\"false\"></span><strong>Lightweight yet warm</strong> for easy layering with jackets or coats</li></ol>', '<p><strong style=\"color: rgb(0, 0, 0);\">Design:</strong><span style=\"color: rgb(0, 0, 0);\"> This hoodie features a prominent SUPRA graphic print, showcasing a bold and urban aesthetic. The eye-catching design adds a contemporary flair, making it a great statement piece that pairs well with various outfits.</span></p><p><strong style=\"color: rgb(0, 0, 0);\">Material:</strong><span style=\"color: rgb(0, 0, 0);\"> Made from high-quality fleece, this hoodie provides exceptional warmth and softness. The plush fabric is breathable, ensuring you stay cozy without overheating, making it suitable for all-day wear.</span></p><p><strong style=\"color: rgb(0, 0, 0);\">Fit:</strong><span style=\"color: rgb(0, 0, 0);\"> Designed with a relaxed fit and full sleeves, it allows for easy movement and comfort. The ribbed cuffs and waistband help to trap heat, making it perfect for cooler weather.</span></p><p><strong style=\"color: rgb(0, 0, 0);\">Functional Features:</strong><span style=\"color: rgb(0, 0, 0);\"> The pullover style includes a spacious kangaroo pocket, ideal for warming your hands or storing small essentials. The adjustable drawstring hood adds versatility and can be tailored to your preference for extra protection against the elements.</span></p><p><br></p><h2><span style=\"color: rgb(33, 33, 33);\">Specifications of</span></h2><ol><li data-list=\"bullet\"><span class=\"ql-ui\" contenteditable=\"false\"></span><span style=\"color: rgb(117, 117, 117);\">Brand</span></li><li data-list=\"bullet\"><span class=\"ql-ui\" contenteditable=\"false\"></span><span style=\"color: rgb(0, 0, 0);\">No Brand</span></li><li data-list=\"bullet\"><span class=\"ql-ui\" contenteditable=\"false\"></span><span style=\"color: rgb(117, 117, 117);\">SKU</span></li><li data-list=\"bullet\"><span class=\"ql-ui\" contenteditable=\"false\"></span><span style=\"color: rgb(0, 0, 0);\">436375825_PK-2714163078</span></li><li data-list=\"bullet\"><span class=\"ql-ui\" contenteditable=\"false\"></span><span style=\"color: rgb(117, 117, 117);\">Apparel</span></li><li data-list=\"bullet\"><span class=\"ql-ui\" contenteditable=\"false\"></span><span style=\"color: rgb(0, 0, 0);\">Not Specified</span></li><li data-list=\"bullet\"><span class=\"ql-ui\" contenteditable=\"false\"></span><span style=\"color: rgb(117, 117, 117);\">Age Range</span></li><li data-list=\"bullet\"><span class=\"ql-ui\" contenteditable=\"false\"></span><span style=\"color: rgb(0, 0, 0);\">Standard</span></li></ol>', 1299, 1099, '[]', '[\"Green\",\"Grey\",\"Orange\",\"Black\"]', '2026-03-08 13:03:59', '[\"[\\\"S\\\",\\\"M\\\",\\\"L\\\",\\\"XL\\\",\\\"XXL\\\"]\"]'),
(28, 'Hinz Men\'s Supreme Summer Vest (Sleeveless)', 'Clothing & Style', 'Men', '<p><strong>Key Features</strong></p><ol><li data-list=\"bullet\"><span class=\"ql-ui\" contenteditable=\"false\"></span><strong>Lightweight &amp; Breathable:</strong> Keeps you cool and fresh during daily wear.</li><li data-list=\"bullet\"><span class=\"ql-ui\" contenteditable=\"false\"></span><strong>Stretchable Material:</strong> Flexible fabric provides ease and all-day comfort.</li><li data-list=\"bullet\"><span class=\"ql-ui\" contenteditable=\"false\"></span><strong>Skin-Friendly Fabric:</strong> Gentle on the skin and suitable for long hours of wear.</li><li data-list=\"bullet\"><span class=\"ql-ui\" contenteditable=\"false\"></span><strong>Versatile Wear:</strong> Ideal as an undershirt, casual homewear, or paired with jeans or shorts.</li><li data-list=\"bullet\"><span class=\"ql-ui\" contenteditable=\"false\"></span><strong>Durable Quality:</strong> Designed to maintain shape and softness even after regular washing.</li><li data-list=\"bullet\"><span class=\"ql-ui\" contenteditable=\"false\"></span><strong>Easy Care:</strong> Simple normal wash care for everyday convenience.</li><li data-list=\"bullet\"><span class=\"ql-ui\" contenteditable=\"false\"></span><strong>Made in Pakistan:</strong> Manufactured with quality standards by Hinz┬«.</li></ol>', '<ol><li data-list=\"bullet\"><span class=\"ql-ui\" contenteditable=\"false\"></span><span style=\"color: rgb(0, 0, 0);\">Made from 100% Premium Cotton Fabric</span></li><li data-list=\"bullet\"><span class=\"ql-ui\" contenteditable=\"false\"></span><span style=\"color: rgb(0, 0, 0);\">Value for Money - Great Comfort at an affordable Price</span></li><li data-list=\"bullet\"><span class=\"ql-ui\" contenteditable=\"false\"></span><span style=\"color: rgb(0, 0, 0);\">Style - Premium Vest with Sleeves</span></li><li data-list=\"bullet\"><span class=\"ql-ui\" contenteditable=\"false\"></span><span style=\"color: rgb(0, 0, 0);\">Manufactured by: Hinz┬«</span></li><li data-list=\"bullet\"><span class=\"ql-ui\" contenteditable=\"false\"></span><span style=\"color: rgb(0, 0, 0);\">Made in Pakistan</span></li><li data-list=\"bullet\"><span class=\"ql-ui\" contenteditable=\"false\"></span><span style=\"color: rgb(0, 0, 0);\">Normal Wash Only</span></li></ol><p><span style=\"color: rgb(0, 0, 0);\">Hinz is the best knitwear brand in Pakistan. The company was established nearly three decades ago and is widely recognized for producing finest quality all weather products for men, women and kids.</span></p><p><span style=\"color: rgb(0, 0, 0);\">Hinz strives for complete customer satisfaction through a relentless focus on understanding customer needs coupled with sustained innovation and implementation of stringent quality control practices, which are in-line with international standards.</span></p><p><span style=\"color: rgb(0, 0, 0);\">Over the years, we have established a sophisticated manufacturing and distribution focused set-up based in Faisalabad, which helps us fulfill the needs of our customers, all over Pakistan.</span></p>', 889, 599, '[]', '[]', '2026-03-08 14:21:21', '[\"[\\\"S\\\",\\\"M\\\",\\\"L\\\",\\\"XL\\\",\\\"XXL\\\"]\"]'),
(29, 'Jackies Three Quarter For Men\'s', 'Clothing & Style', 'Men', '<p><strong>Key Features</strong></p><ol><li data-list=\"bullet\"><span class=\"ql-ui\" contenteditable=\"false\"></span><strong>Premium Quality Fabric:</strong> Made from soft and durable material for long-lasting comfort.</li><li data-list=\"bullet\"><span class=\"ql-ui\" contenteditable=\"false\"></span><strong>Breathable &amp; Lightweight:</strong> Keeps you cool and comfortable during warm weather.</li><li data-list=\"bullet\"><span class=\"ql-ui\" contenteditable=\"false\"></span><strong>Elastic Waistband:</strong> Flexible waistband with adjustable drawstring for a secure fit.</li><li data-list=\"bullet\"><span class=\"ql-ui\" contenteditable=\"false\"></span><strong>Side Pockets:</strong> Convenient pockets to carry small essentials like phone or keys.</li><li data-list=\"bullet\"><span class=\"ql-ui\" contenteditable=\"false\"></span><strong>Perfect for Multiple Activities:</strong> Ideal for gym, jogging, sports, lounging, or casual outings.</li><li data-list=\"bullet\"><span class=\"ql-ui\" contenteditable=\"false\"></span><strong>Easy to Maintain:</strong> Machine washable fabric that retains shape and color after washing.</li><li data-list=\"bullet\"><span class=\"ql-ui\" contenteditable=\"false\"></span><strong>Modern Casual Style:</strong> Trendy design that pairs well with t-shirts, vests, and hoodies</li></ol>', '<ol><li data-list=\"bullet\"><span class=\"ql-ui\" contenteditable=\"false\"></span>SUMMER THREE QUARTER WITH ELASTICATED WAISTBAND AND ADJUSTABLE DRAWCORD</li><li data-list=\"bullet\"><span class=\"ql-ui\" contenteditable=\"false\"></span>TWO WELT BACK POCKET WITH FLAP AND CARGO POCKET WITH FLAP</li><li data-list=\"bullet\"><span class=\"ql-ui\" contenteditable=\"false\"></span>COMFORTABLE &amp; TRENDY</li><li data-list=\"bullet\"><span class=\"ql-ui\" contenteditable=\"false\"></span><strong>Comfortable Fit:</strong> Designed to provide a relaxed fit for everyday wear.</li><li data-list=\"bullet\"><span class=\"ql-ui\" contenteditable=\"false\"></span><strong>Three-Quarter Length Design:</strong> Stylish length that sits below the knee, perfect for casual and sports activities.</li></ol>', 1999, 1449, '[]', '[\"Blue\",\"Green\",\"Black\",\"Grey\"]', '2026-03-08 14:33:08', '[\"[\\\"M\\\",\\\"L\\\",\\\"XL\\\",\\\"XXL\\\"]\"]'),
