(33, 'Graduation Convocation Gown - Premium Quality', 'Clothing & Style', 'Women', '<p><strong>Key Features</strong></p><ol><li data-list=\"bullet\"><span class=\"ql-ui\" contenteditable=\"false\"></span><strong>Premium Quality Fabric:</strong> Made from high-quality material for a professional and elegant look.</li><li data-list=\"bullet\"><span class=\"ql-ui\" contenteditable=\"false\"></span><strong>Comfortable Fit:</strong> Lightweight and breathable fabric ensures comfort during long events.</li><li data-list=\"bullet\"><span class=\"ql-ui\" contenteditable=\"false\"></span><strong>Elegant &amp; Formal Appearance:</strong> Designed to give a dignified and polished graduation look.</li><li data-list=\"bullet\"><span class=\"ql-ui\" contenteditable=\"false\"></span><strong>Durable Stitching:</strong> Strong stitching for long-lasting use and reliability.</li><li data-list=\"bullet\"><span class=\"ql-ui\" contenteditable=\"false\"></span><strong>Easy to Wear:</strong> Simple front design for quick and convenient dressing.</li><li data-list=\"bullet\"><span class=\"ql-ui\" contenteditable=\"false\"></span><strong>Reusable Quality:</strong> High-quality fabric allows the gown to be used multiple times.</li></ol>', '<p><span style=\"background-color: rgb(255, 255, 255); color: rgb(0, 0, 0);\">Elevate your special occasion with this premium Teacher/Lawyer/Graduation/Convocation Gown, designed for adults. Crafted with exceptional quality and attention to detail, this gown offers a professional and polished appearance. Key Features: High-Quality Material Made from durable and premium-grade fabric for long-lasting wear. Excellent Stitching Expertly stitched to ensure a flawless fit and finish. Versatile Usage Ideal for graduation ceremonies, convocation events, teaching, and legal professions. Product Highlights: Suitable for general adult sizing, offering a comfortable and universal fit. Unused and perfectly tailored for a professional look. A timeless design that complements formal and academic occasions. Experience unmatched quality and elegance with this versatile gown, tailored for important milestones and professional attire.</span></p>', 2579, 1999, '[]', '[]', '2026-03-08 16:07:06', '[\"[\\\"S\\\",\\\"M\\\",\\\"L\\\"]\"]'),
(34, 'Stylish 2-Piece Suit for Women/Girls - Linen, Comfortable', 'Clothing & Style', 'Women', '<p><strong>Key Features</strong></p><ol><li data-list=\"bullet\"><span class=\"ql-ui\" contenteditable=\"false\"></span><strong>Premium Linen Fabric</strong></li><li data-list=\"bullet\"><span class=\"ql-ui\" contenteditable=\"false\"></span><strong>Two-Piece Set</strong></li><li data-list=\"bullet\"><span class=\"ql-ui\" contenteditable=\"false\"></span><strong>Comfortable &amp; Lightweight</strong></li><li data-list=\"bullet\"><span class=\"ql-ui\" contenteditable=\"false\"></span><strong>Modern Design</strong></li><li data-list=\"bullet\"><span class=\"ql-ui\" contenteditable=\"false\"></span><strong>Relaxed Fit</strong></li><li data-list=\"bullet\"><span class=\"ql-ui\" contenteditable=\"false\"></span><strong>Durable Stitching</strong></li><li data-list=\"bullet\"><span class=\"ql-ui\" contenteditable=\"false\"></span><strong>Versatile Wear</strong></li><li data-list=\"bullet\"><span class=\"ql-ui\" contenteditable=\"false\"></span><strong>Easy to Maintain</strong></li><li data-list=\"bullet\"><span class=\"ql-ui\" contenteditable=\"false\"></span><strong>Stylish &amp; Trendy Look</strong></li></ol>', '<p><span style=\"color: rgb(0, 0, 0);\">Fabric: Made from soft, breathable, and durable linen material, ensuring comfort and longevity. Style: Modern and stylish design, ideal for girls and women seeking a versatile and fashionable outfit. Size: Standard size with measurements: Chest 21\", Length 34\", Trouser Length 38\". Comfort: Designed to provide a comfortable and flattering fit for various body types. This 2-piece suit is a must-have for any wardrobe, offering both style and comfort in a sleek, easy-to-wear design.</span></p><h2><span style=\"color: rgb(33, 33, 33);\">Specifications of</span></h2><ol><li data-list=\"bullet\"><span class=\"ql-ui\" contenteditable=\"false\"></span><span style=\"color: rgb(117, 117, 117);\">Brand</span></li><li data-list=\"bullet\">