(39, 'Baby Girl Suit fancy Dresses for kids 1 to 7 year', 'Clothing & Style', 'Kids', '<p><strong style=\"background-color: rgb(255, 255, 255); color: rgb(0, 0, 0);\">Key Features:</strong></p><ol><li data-list=\"bullet\"><span class=\"ql-ui\" contenteditable=\"false\"></span><span style=\"background-color: rgb(255, 255, 255); color: rgb(0, 0, 0);\">Luxuriously soft Malai Jersey fabric</span></li><li data-list=\"bullet\"><span class=\"ql-ui\" contenteditable=\"false\"></span><span style=\"background-color: rgb(255, 255, 255); color: rgb(0, 0, 0);\">Breathable and lightweight for year-round comfort</span></li><li data-list=\"bullet\"><span class=\"ql-ui\" contenteditable=\"false\"></span><span style=\"background-color: rgb(255, 255, 255); color: rgb(0, 0, 0);\">Stylish and versatile color options</span></li><li data-list=\"bullet\"><span class=\"ql-ui\" contenteditable=\"false\"></span><span style=\"background-color: rgb(255, 255, 255); color: rgb(0, 0, 0);\">Elasticized waistband for a secure fit</span></li><li data-list=\"bullet\"><span class=\"ql-ui\" contenteditable=\"false\"></span><span style=\"background-color: rgb(255, 255, 255); color: rgb(0, 0, 0);\">Perfect for lounging, sleeping, or casual outings</span></li><li data-list=\"bullet\"><span class=\"ql-ui\" contenteditable=\"false\"></span><span style=\"background-color: rgb(255, 255, 255); color: rgb(0, 0, 0);\">Easy to care for, machine washable</span></li></ol>', '<ol><li data-list=\"bullet\"><span class=\"ql-ui\" contenteditable=\"false\"></span><span style=\"color: rgb(0, 0, 0);\">Brand - Happy Nestings </span></li><li data-list=\"bullet\"><span class=\"ql-ui\" contenteditable=\"false\"></span><span style=\"color: rgb(0, 0, 0);\">Stuff - Malai Jersey</span></li><li data-list=\"bullet\"><span class=\"ql-ui\" contenteditable=\"false\"></span><span style=\"color: rgb(0, 0, 0);\">Colour - White </span></li><li data-list=\"bullet\"><span class=\"ql-ui\" contenteditable=\"false\"></span><span style=\"color: rgb(0, 0, 0);\">Trouser Colour - Mustard, Blue, Purple</span></li><li data-list=\"bullet\"><span class=\"ql-ui\" contenteditable=\"false\"></span><span style=\"color: rgb(0, 0, 0);\">Size - 1 to 7 year</span></li><li data-list=\"bullet\"><span class=\"ql-ui\" contenteditable=\"false\"></span><span style=\"color: rgb(0, 0, 0);\">We Are Send Random Trousers</span></li></ol><p><span style=\"color: rgb(0, 0, 0);\">Introducing the Happy Nestings Malai Jersey Loungewear Set ŌĆō your ticket to unparalleled comfort and style! Elevate your relaxation game with this exquisite loungewear ensemble, available exclusively on Daraz.</span></p><p><br></p><p><strong style=\"color: rgb(0, 0, 0);\">Brand: Happy Nestings</strong><span style=\"color: rgb(0, 0, 0);\"> Experience the bliss of nestling into happiness with our premium loungewear collection. Crafted with care and designed to pamper, Happy Nestings brings you a Malai Jersey Loungewear Set that\'s both luxurious and cozy.</span></p><p><strong style=\"color: rgb(0, 0, 0);\">Material: Malai Jersey</strong><span style=\"color: rgb(0, 0, 0);\"> Our loungewear set is made from the finest Malai Jersey fabric, ensuring a soft, silky touch against your skin. This high-quality material drapes beautifully and is incredibly breathable, making it perfect for all-day wear.</span></p><p><strong style=\"color: rgb(0, 0, 0);\">Color: White</strong><span style=\"color: rgb(0, 0, 0);\"> The pure, pristine White hue of this loungewear set exudes elegance and sophistication. Whether you\'re lounging at home or hosting a cozy gathering, this pristine color will make you feel effortlessly stylish.</span></p><p><strong style=\"color: rgb(0, 0, 0);\">Trouser Color Options: Mustard, Blue, Purple</strong><span style=\"color: rgb(0, 0, 0);\"> Add a pop of color to your loungewear wardrobe with our range of vibrant trouser options. Choose from Mustard for a sunny disposition, Blue for a calming aura, or Purple for a touch of royalty. Mix and match to suit your mood and style!</span></p><p><strong style=\"color: rgb(0, 0, 0);\">Available Sizes: 1 year to 7 years</strong><span style=\"color: rgb(0, 0, 0);\"> We understand that comfort comes in all shapes and sizes. That\'s why our Happy Nestings Malai Jersey Loungewear Set is available in a range of sizes: Small, Medium, and Large. Find the perfect fit that embraces your body and offers unparalleled comfort.</span></p>', 8099, 546, '[]', '[\"White\",\"Black\"]', '2026-03-08 17:20:28', '[\"[]\"]'),
(40, 'Boys Gilet Upper', 'Clothing & Style', 'Kids', '<p><strong>Key Features ŌĆō Boy Upper</strong></p><ol><li data-list=\"bullet\"><span class=\"ql-ui\" contenteditable=\"false\"></span>Cotton Fabric</li><li data-list=\"bullet\"><span class=\"ql-ui\" contenteditable=\"false\"></span>Comfortable Fit</li><li data-list=\"bullet\"><span class=\"ql-ui\" contenteditable=\"false\"></span>Soft &amp; Breathable Material</li><li data-list=\"bullet\"><span class=\"ql-ui\" contenteditable=\"false\"></span>Durable Stitching</li><li data-list=\"bullet\"><span class=\"ql-ui\" contenteditable=\"false\"></span>Lightweight for Daily Wear</li><li data-list=\"bullet\"><span class=\"ql-ui\" contenteditable=\"false\"></span>Easy to Wash</li><li data-list=\"bullet\"><span class=\"ql-ui\" contenteditable=\"false\"></span>Casual &amp; Everyday Style</li><li data-list=\"bullet\"><span class=\"ql-ui\" contenteditable=\"false\"></span>Flexible &amp; Stretchable</li><li data-list=\"bullet\"><span class=\"ql-ui\" contenteditable=\"false\"></span>Perfect for School &amp; Play</li></ol>', '<p><span style=\"background-color: rgb(255, 255, 255); color: rgb(81, 81, 103);\">This Boy Upper utilizes technical fleece with a specialized fiber configuration engineered for optimal thermal performance. The precision-calibrated construction creates microscopic air chambers that trap body heat while allowing excess moisture vapor to escape through controlled permeability channels. The material demonstrates exceptional resilience against deformation, maintaining its insulative properties through extended wear cycles. Strategic reinforcement at high-stress zones ensures durability without compromising the garment\'s inherent flexibility during dynamic movement patterns.</span></p>', 1990, 1744, '[]', '[\"Blue\",\"Brown\"]', '2026-03-08 17:29:21', '[\"[\\\"S\\\",\\\"M\\\"]\"]'),
(41, 'Komfy Printed Suit For Boys', 'Clothing & Style', 'Kids', '<p><strong>Key Features</strong></p><ol><li data-list=\"bullet\"><span class=\"ql-ui\" contenteditable=\"false\"></span>Soft &amp; Comfortable Fabric</li><li data-list=\"bullet\"><span class=\"ql-ui\" contenteditable=\"false\"></span>Stylish Printed Design</li><li data-list=\"bullet\"><span class=\"ql-ui\" contenteditable=\"false\"></span>Lightweight &amp; Breathable</li><li data-list=\"bullet\"><span class=\"ql-ui\" contenteditable=\"false\"></span>Comfortable Fit for Kids</li><li data-list=\"bullet\"><span class=\"ql-ui\" contenteditable=\"false\"></span>Durable Stitching</li><li data-list=\"bullet\"><span class=\"ql-ui\" contenteditable=\"false\"></span>Perfect for Casual Wear</li><li data-list=\"bullet\"><span class=\"ql-ui\" contenteditable=\"false\"></span>Skin-Friendly Material</li><li data-list=\"bullet\"><span class=\"ql-ui\" contenteditable=\"false\"></span>Easy to Wash</li><li data-list=\"bullet\"><span class=\"ql-ui\" contenteditable=\"false\"></span>Ideal for Daily Wear</li></ol>', '<p>Keep your little one stylish and comfortable with the Komfy Printed Suit for Boys. Designed for everyday wear, this outfit features a trendy printed design that adds a fun and modern touch to your childŌĆÖs wardrobe. Made from soft, breathable fabric, it ensures maximum comfort throughout the day whether at home, school, or outdoor play. The relaxed fit allows easy movement, making it a perfect choice for active kids.</p>', 120, 875, '[]', '[\"Blue\",\"Green\",\"Black\",\"Yellow\"]', '2026-03-08 17:39:18', '[\"[\\\"S\\\",\\\"M\\\"]\"]'),
(42, 'Boys Printed T-Shirt', 'Clothing & Style', 'Kids', '<p><strong>Key Features:</strong></p><ol><li data-list=\"bullet\"><span class=\"ql-ui\" contenteditable=\"false\"></span>Premium quality soft cotton fabric</li><li data-list=\"bullet\"><span class=\"ql-ui\" contenteditable=\"false\"></span>Trendy and stylish printed design</li><li data-list=\"bullet\"><span class=\"ql-ui\" contenteditable=\"false\"></span>Comfortable and breathable for all-day wear</li><li data-list=\"bullet\"><span class=\"ql-ui\" contenteditable=\"false\"></span>Perfect for casual outings and daily use</li><li data-list=\"bullet\"><span class=\"ql-ui\" contenteditable=\"false\"></span>Durable stitching for long-lasting use</li><li data-list=\"bullet\"><span class=\"ql-ui\" contenteditable=\"false\"></span>Lightweight and skin-friendly material</li><li data-list=\"bullet\"><span class=\"ql-ui\" contenteditable=\"false\"></span>Easy to wash and maintain</li><li data-list=\"bullet\"><span class=\"ql-ui\" contenteditable=\"false\"></span>Ideal for boys of all ages</li><li data-list=\"bullet\"><span class=\"ql-ui\" contenteditable=\"false\"></span>Modern fit for a smart and cool look</li><li data-list=\"bullet\"><span class=\"ql-ui\" contenteditable=\"false\"></span>Great choice for summer wear ŌśĆ’ĖÅ</li></ol>', '<p><strong style=\"background-color: rgb(255, 255, 255); color: rgb(81, 81, 103);\">FABRIC: ??SINGLE JERSY ,100% COTTON??</strong></p><p><strong style=\"background-color: rgb(255, 255, 255); color: rgb(81, 81, 103);\">CARE INSTRUCTIONS:</strong></p><ol><li data-list=\"bullet\"><span class=\"ql-ui\" contenteditable=\"false\"></span><span style=\"background-color: rgb(255, 255, 255); color: rgb(81, 81, 103);\">Machine or handwash upto 30??C/86F</span></li><li data-list=\"bullet\"><span class=\"ql-ui\" contenteditable=\"false\"></span><span style=\"background-color: rgb(255, 255, 255); color: rgb(81, 81, 103);\">Gentle cycle</span></li><li data-list=\"bullet\"><span class=\"ql-ui\" contenteditable=\"false\"></span><span style=\"background-color: rgb(255, 255, 255); color: rgb(81, 81, 103);\">Do not dry in direct sunlight</span></li><li data-list=\"bullet\"><span class=\"ql-ui\" contenteditable=\"false\"></span><span style=\"background-color: rgb(255, 255, 255); color: rgb(81, 81, 103);\">Do not bleach</span></li><li data-list=\"bullet\"><span class=\"ql-ui\" contenteditable=\"false\"></span><span style=\"background-color: rgb(255, 255, 255); color: rgb(81, 81, 103);\">Do not iron directly on prints/embroidery</span></li></ol>', 1587, 1189, '[]', '[\"White\",\"Black\",\"Blue\"]', '2026-03-08 17:48:03', '[\"[\\\"S\\\",\\\"M\\\"]\"]'),
(43, 'Embroidered Cambric Coral Girls 2PC', 'Clothing & Style', 'Kids', '<p><strong>Key Features:</strong></p><ol><li data-list=\"bullet\"><span class=\"ql-ui\" contenteditable=\"false\"></span>Premium cambric fabric for soft and comfortable wear</li><li data-list=\"bullet\"><span class=\"ql-ui\" contenteditable=\"false\"></span>Beautiful coral color with elegant embroidery</li><li data-list=\"bullet\"><span class=\"ql-ui\" contenteditable=\"false\"></span>Stylish 2-piece set for girls</li><li data-list=\"bullet\"><span class=\"ql-ui\" contenteditable=\"false\"></span>Lightweight and breathable material</li><li data-list=\"bullet\"><span class=\"ql-ui\" contenteditable=\"false\"></span>Perfect for casual wear and small gatherings</li><li data-list=\"bullet\"><span class=\"ql-ui\" contenteditable=\"false\"></span>Fine stitching for durability and long-lasting use</li><li data-list=\"bullet\"><span class=\"ql-ui\" contenteditable=\"false\"></span>Comfortable fit for all-day wear</li><li data-list=\"bullet\"><span class=\"ql-ui\" contenteditable=\"false\"></span>Easy to wash and maintain</li><li data-list=\"bullet\"><span class=\"ql-ui\" contenteditable=\"false\"></span>Trendy and graceful design for a charming look Ō£©</li></ol>', '<p>The <strong>Embroidered Cambric Coral Girls 2PC Suit</strong> is a perfect combination of elegance and comfort for young girls. Designed in a beautiful coral shade, this outfit features delicate embroidery that adds a graceful and stylish touch. Made from soft cambric fabric, it is lightweight and breathable, ensuring all-day comfort. The matching shirt and trouser create a coordinated look that is ideal for casual wear, family gatherings, and festive occasions. This stylish 2-piece suit is a lovely addition to any girlŌĆÖs wardrobe.</p><p><strong>Highlights:</strong></p><ol><li data-list=\"bullet\"><span class=\"ql-ui\" contenteditable=\"false\"></span><strong>Elegant Embroidered Design</strong></li><li data-list=\"bullet\"><span class=\"ql-ui\" contenteditable=\"false\"></span><strong>Soft &amp; Breathable Cambric Fabric</strong></li><li data-list=\"bullet\"><span class=\"ql-ui\" contenteditable=\"false\"></span><strong>Beautiful Coral Color</strong></li><li data-list=\"bullet\"><span class=\"ql-ui\" contenteditable=\"false\"></span><strong>Comfortable 2-Piece Outfit</strong></li><li data-list=\"bullet\"><span class=\"ql-ui\" contenteditable=\"false\"></span><strong>Perfect for Casual &amp; Festive Wear</strong> Ō£©????</li></ol>', 4290, 3280, '[]', '[\"Green\",\"Black\",\"Blue\",\"Orange\"]', '2026-03-08 18:00:41', '[\"[\\\"S\\\",\\\"M\\\"]\"]'),
(44, 'Kids Mania Love Blossom Tunic Set', 'Clothing & Style', 'Kids', '<h2><span style=\"color: rgb(20, 20, 20);\">Product Details</span></h2><table><tbody><tr><td data-row=\"1\"><span style=\"color: rgb(66, 66, 66); background-color: rgb(250, 250, 250);\">Color Type</span></td><td data-row=\"1\"><span style=\"color: rgb(66, 66, 66);\">Purple heart</span></td></tr><tr><td data-row=\"2\"><span style=\"color: rgb(66, 66, 66); background-color: rgb(250, 250, 250);\">Product ID</span></td><td data-row=\"2\"><span style=\"color: rgb(66, 66, 66);\">SKB6187</span></td></tr><tr><td data-row=\"3\"><span style=\"color: rgb(66, 66, 66); background-color: rgb(250, 250, 250);\">Fabric</span></td><td data-row=\"3\"><span style=\"color: rgb(66, 66, 66);\">Cotton</span></td></tr><tr><td data-row=\"4\"><span style=\"color: rgb(66, 66, 66); background-color: rgb(250, 250, 250);\">Number Of Pieces</span></td><td data-row=\"4\"><span style=\"color: rgb(66, 66, 66);\">2 piece</span></td></tr><tr><td data-row=\"5\"><span style=\"color: rgb(66, 66, 66); background-color: rgb(250, 250, 250);\">Season</span></td><td data-row=\"5\"><span style=\"color: rgb(66, 66, 66);\">Summer wear</span></td></tr></tbody></table>', '<p><span style=\"color: rgb(66, 66, 66);\">This adorable 2-Piece Cotton Frock in Purple Heart is perfect for summer wear. Featuring a charming design with a playful color scheme, this outfit is ideal for little girls. The comfortable fabric ensures a breathable experience, making it a must-have for any wardrobe. Let your child stand out in style with this lovely frock from Kids Mania.</span></p><p><span style=\"color: rgb(66, 66, 66);\">Disclaimer:</span></p><p><span style=\"color: rgb(66, 66, 66);\">Actual product color may vary slightly from the image.</span></p><p><span style=\"color: rgb(20, 20, 20);\">Shopping Security</span></p><p><span style=\"color: rgb(6, 118, 71);\">Safe Payment</span></p><p><span style=\"color: rgb(6, 118, 71);\">Secure Logistics</span></p><p><span s