(46, 'Brown Rubber Sole Cow Leather Formal', 'Footwear', 'Formal Shoes', '<p><strong>Key Features:</strong></p><ol><li data-list=\"bullet\"><span class=\"ql-ui\" contenteditable=\"false\"></span>Premium cow leather upper for a refined and elegant look</li><li data-list=\"bullet\"><span class=\"ql-ui\" contenteditable=\"false\"></span>Durable brown rubber sole for excellent grip and comfort</li><li data-list=\"bullet\"><span class=\"ql-ui\" contenteditable=\"false\"></span>Classic formal design perfect for office and events</li><li data-list=\"bullet\"><span class=\"ql-ui\" contenteditable=\"false\"></span>Soft inner lining for all-day comfort</li><li data-list=\"bullet\"><span class=\"ql-ui\" contenteditable=\"false\"></span>Strong stitching for long-lasting durability</li><li data-list=\"bullet\"><span class=\"ql-ui\" contenteditable=\"false\"></span>Stylish and versatile to pair with formal outfits</li><li data-list=\"bullet\"><span class=\"ql-ui\" contenteditable=\"false\"></span>Slip-resistant sole for better stability</li></ol>', '<p><span style=\"background-color: rgb(255, 255, 255); color: rgb(81, 81, 103);\">Elevate your formal footwear with our Black Rubber Sole Cow Leather Double Monk Strap Shoes. Crafted from premium cow leather, these shoes blend traditional elegance with modern comfort. The sleek double monk strap design adds a distinctive flair, perfect for formal occasions and professional settings. With a durable rubber sole, these shoes offer excellent grip and all-day comfort, ensuring you look stylish and feel confident wherever you go.</span></p><p><br></p><p><span style=\"background-color: rgb(255, 255, 255); color: rgb(81, 81, 103);\">It\'s courier policy that customers are not allowed to open parcels before delivery. If there is an issue we will resolve it for you, all you have to do is contact us</span></p>', 2890, 2275, '[\"US/PAK 6\",\"US/PAK 7\",\"US/PAK 8\",\"US/PAK 9\",\"US/PAK 10\",\"US/PAK 11\"]', '[]', '2026-03-08 18:28:52', '[\"[]\"]'),
