(89, 'Underarm Whitening Cream', 'Beauty & Wellness', 'Skin Treatments', '<p><strong>Key Features</strong></p><ol><li data-list=\"bullet\"><span class=\"ql-ui\" contenteditable=\"false\"></span><strong>Brightens Dark Underarms:</strong> Helps reduce darkness and promotes a more even skin tone.</li><li data-list=\"bullet\"><span class=\"ql-ui\" contenteditable=\"false\"></span><strong>Deep Nourishment:</strong> Enriched with moisturizing ingredients to keep underarm skin soft and hydrated.</li><li data-list=\"bullet\"><span class=\"ql-ui\" contenteditable=\"false\"></span><strong>Gentle Skin Formula:</strong> Suitable for delicate underarm skin with a mild, non-irritating formula.</li><li data-list=\"bullet\"><span class=\"ql-ui\" contenteditable=\"false\"></span><strong>Helps Reduce Pigmentation:</strong> Works to minimize discoloration caused by shaving, sweat, or friction.</li><li data-list=\"bullet\"><span class=\"ql-ui\" contenteditable=\"false\"></span><strong>Smooth &amp; Soft Skin:</strong> Improves skin texture for a smoother and healthier look.</li><li data-list=\"bullet\"><span class=\"ql-ui\" contenteditable=\"false\"></span><strong>Quick Absorption:</strong> Lightweight cream that absorbs easily without leaving a sticky feeling.</li><li data-list=\"bullet\"><span class=\"ql-ui\" contenteditable=\"false\"></span><strong>Daily Use Friendly:</strong> Safe for regular use to maintain brighter underarms.</li><li data-list=\"bullet\"><span class=\"ql-ui\" contenteditable=\"false\"></span><strong>Fresh &amp; Clean Feel:</strong> Helps keep underarms feeling fresh and comfortable throughout the day.</li></ol>', '<p><span style=\"background-color: rgb(255, 255, 255); color: rgb(81, 81, 103);\">Reveal visibly brighter and more even-toned skin in your most delicate areas with our </span><strong style=\"background-color: rgb(255, 255, 255); color: rgb(81, 81, 103);\">Underarm Whitening Cream</strong><span style=\"background-color: rgb(255, 255, 255); color: rgb(81, 81, 103);\">. Specially designed for </span><strong style=\"background-color: rgb(255, 255, 255); color: rgb(81, 81, 103);\">sensitive zones</strong><span style=\"background-color: rgb(255, 255, 255); color: rgb(81, 81, 103);\">. This cream is enriched with brightening actives and skin-nourishing ingredients.</span></p><p><span style=\"background-color: rgb(255, 255, 255); color: rgb(81, 81, 103);\">Formulated with </span><strong style=\"background-color: rgb(255, 255, 255); color: rgb(81, 81, 103);\">collagen, antioxidants</strong><span style=\"background-color: rgb(255, 255, 255); color: rgb(81, 81, 103);\">, and a unique brightening complex, it not only corrects uneven tone but also improves the skinŌĆÖs elasticity and moisture levels. The cream works from within to energize tired, discolored skin, promoting cell turnover and gradually reducing melanin buildup. With regular use, it restores confidence and smooth, radiant skin without irritation or greasiness.</span></p><p><span style=\"background-color: rgb(255, 255, 255); color: rgb(81, 81, 103);\">This cream is enriched with brightening and moisturizing ingredients that rapidly penetrate the skin, helping to reduce melanin, improve dullness, and even out skin tone. It enhances the skin\'s lightening ability, leaving it fair, smooth, moisturized, and elastic.</span></p><p><br></p><p><strong style=\"background-color: rgb(255, 255, 255); color: rgb(81, 81, 103);\">Underarm Lightening Cream (</strong><span style=\"background-color: rgb(255, 255, 255); color: rgb(81, 81, 103);\">For Sensitive Areas</span><strong style=\"background-color: rgb(255, 255, 255); color: rgb(81, 81, 103);\">)</strong></p><p><span style=\"background-color: rgb(255, 255, 255); color: rgb(81, 81, 103);\">Underarm &amp; Sensitive Parts Lightening Cream</span></p><p><span style=\"background-color: rgb(255, 255, 255); color: rgb(81, 81, 103);\">With Collagen, Brightening Complex, Concealer &amp; Solid Light Texture</span></p><p><span style=\"background-color: rgb(255, 255, 255); color: rgb(81, 81, 103);\">Powerful Antioxidants Energize</span></p><p><strong style=\"background-color: rgb(255, 255, 255); color: rgb(81, 81, 103);\">Net Weight:</strong><span style=\"background-color: rgb(255, 255, 255); color: rgb(81, 81, 103);\"> 60g </span></p><p><br></p><p><strong style=\"background-color: rgb(255, 255, 255); color: rgb(81, 81, 103);\">Usage:</strong></p><p><span style=\"background-color: rgb(255, 255, 255); color: rgb(81, 81, 103);\">After cleansing your skin or before going outside, apply the cream to underarms or other desired areas. Gently massage until fully absorbed.</span></p><p><br></p><p><strong style=\"background-color: rgb(255, 255, 255); color: rgb(81, 81, 103);\">Ō£© What\'s in it:</strong></p><p><strong style=\"background-color: rgb(255, 255, 255); color: rgb(81, 81, 103);\">ŌĆó </strong><span style=\"background-color: rgb(255, 255, 255); color: rgb(81, 81, 103);\">Collagen</span></p><p><strong style=\"background-color: rgb(255, 255, 255); color: rgb(81, 81, 103);\">ŌĆó </strong><span style=\"background-color: rgb(255, 255, 255); color: rgb(81, 81, 103);\">Brightening Complex</span></p><p><strong style=\"background-color: rgb(255, 255, 255); color: rgb(81, 81, 103);\">ŌĆó </strong><span style=\"background-color: rgb(255, 255, 255); color: rgb(81, 81, 103);\">Concealer &amp; Solid Light Texture</span></p><p><strong style=\"background-color: rgb(255, 255, 255); color: rgb(81, 81, 103);\">ŌĆó </strong><span style=\"background-color: rgb(255, 255, 255); color: rgb(81, 81, 103);\">Powerful Antioxidants</span></p>', 1349, 1012, '[]', '[]', '2026-03-09 16:44:01', '[\"[]\"]'),
(90, 'Whitening Expert Face Polisher Peeling Cream & Brightening Polish', 'Beauty & Wellness', 'Skin Treatments', '<p><strong>Key Features</strong></p><ol><li data-list=\"bullet\"><span class=\"ql-ui\" contenteditable=\"false\"></span><strong>Exfoliates Dead Skin:</strong> Gently removes dead skin cells for a smoother, refreshed complexion.</li><li data-list=\"bullet\"><span class=\"ql-ui\" contenteditable=\"false\"></span><strong>Brightens Skin Tone:</strong> Helps reduce dullness and promotes a radiant, even skin tone.</li><li data-list=\"bullet\"><span class=\"ql-ui\" contenteditable=\"false\"></span><strong>Deep Cleansing Action:</strong> Clears impurities and unclogs pores for healthier-looking skin.</li><li data-list=\"bullet\"><span class=\"ql-ui\" contenteditable=\"false\"></span><strong>Peeling &amp; Polishing in One:</strong> Combines mild peeling with polishing action for a soft, glowing face.</li><li data-list=\"bullet\"><span class=\"ql-ui\" contenteditable=\"false\"></span><strong>Hydrating Formula:</strong> Leaves skin moisturized and prevents dryness after exfoliation.</li><li data-list=\"bullet\"><span class=\"ql-ui\" contenteditable=\"false\"></span><strong>Refines Skin Texture:</strong> Reduces rough patches and improves overall skin smoothness.</li><li data-list=\"bullet\"><span class=\"ql-ui\" contenteditable=\"false\"></span><strong>Suitable for Daily Use:</strong> Gentle enough for regular use without irritation.</li><li data-list=\"bullet\"><span class=\"ql-ui\" contenteditable=\"false\"></span><strong>Boosts Absorption of Skincare:</strong> Prepares skin to better absorb serums and moisturizers.</li></ol>', '<p><span style=\"background-color: rgb(255, 255, 255); color: rgb(81, 81, 103);\">Transform your skincare routine with the </span><strong style=\"background-color: rgb(255, 255, 255); color: rgb(81, 81, 103);\">Whitening Expert Face Polisher</strong><span style=\"background-color: rgb(255, 255, 255); color: rgb(81, 81, 103);\"> from </sp